+/// Auto-commit changes made by forage execution
+fn auto_commit_changes(
+    item: &ForageOpportunity,
+    changed_files: &[String],
+    args: &ForageArgs,
+) -> Result<()> {
+    let cwd = std::env::current_dir().context("Failed to get current directory")?;
+
+    // Stage all changed files
+    for file in changed_files {
+        let stage_result = Command::new("git")
+            .args(["add", file])
+            .current_dir(&cwd)
+            .output()
+            .context("Failed to stage file")?;
+        if !stage_result.status.success() {
+            tracing::warn!(file = %file, "Failed to stage file for commit");
+        }
+    }
+
+    // Build commit message with OKR context
+    let commit_message = format!(
+        "forage: {} via '{}' engine\n\nOKR: {}\nKR: {}\nEngine: {}\nModel: {}",
+        item.key_result_title,
+        args.execution_engine,
+        item.okr_title,
+        item.key_result_title,
+        args.execution_engine,
+        args.model.as_deref().unwrap_or("default")
+    );
+
+    // Create the commit
+    let commit_result = Command::new("git")
+        .args(["commit", "-m", &commit_message])
+        .current_dir(&cwd)
+        .output()
+        .context("Failed to create commit")?;
+
+    if !commit_result.status.success() {
+        let stderr = String::from_utf8_lossy(&commit_result.stderr);
+        // Don't fail if there's nothing to commit
+        if !stderr.contains("nothing to commit") {
+            anyhow::bail!("Git commit failed: {}", stderr);
+        }
+    }
+
+    tracing::info!(
+        okr_id = %item.okr_id,
+        kr_id = %item.key_result_id,
+        files = changed_files.len(),
+        "Auto-committed forage changes"
+    );
+
+    Ok(())
+}
