115 | #[derive(Debug, Clone)]
116 | pub struct RalphStoryInfo {
117 |     pub id: String,
118 |     pub title: String,
119 |     pub status: RalphStoryStatus,
120 |     pub priority: u8,
121 |     pub depends_on: Vec<String>,
