144 | /// State for the Ralph view
145 | #[derive(Debug, Default)]
146 | pub struct RalphViewState {
147 |     /// Whether Ralph mode is active
148 |     pub active: bool,
149 |     /// Project name
150 |     pub project: String,
151 |     /// Feature name
152 |     pub feature: String,
153 |     /// All stories
154 |     pub stories: Vec<RalphStoryInfo>,
155 |     /// Current iteration
156 |     pub current_iteration: usize,
157 |     /// Maximum iterations
158 |     pub max_iterations: usize,
159 |     /// Whether execution is complete
160 |     pub complete: bool,
161 |     /// Final status string
162 |     pub final_status: Option<String>,
163 |     /// Any error message
164 |     pub error: Option<String>,
165 |     /// Currently selected story index
166 |     pub selected_index: usize,
167 |     /// Whether we're in detail mode (viewing a single story's agent)
168 |     pub detail_mode: bool,
169 |     /// Scroll offset within the detail view
170 |     pub detail_scroll: usize,
171 |     /// ListState for StatefulWidget rendering
172 |     pub list_state: ListState,
173 | }
174 | 
175 | impl RalphViewState {
176 |     pub fn new() -> Self {
177 |         Self::default()
178 |     }
179 | 
180 |     /// Handle a Ralph event
181 |     pub fn handle_event(&mut self, event: RalphEvent) {
182 |         match event {
183 |             RalphEvent::Started {
184 |                 project,
185 |                 feature,
186 |                 stories,
187 |                 max_iterations,
188 |             } => {
189 |                 self.active = true;
190 |                 self.project = project;
191 |                 self.feature = feature;
192 |                 self.stories = stories;
193 |                 self.max_iterations = max_iterations;
194 |                 self.current_iteration = 0;
195 |                 self.complete = false;
196 |                 self.final_status = None;
197 |                 self.error = None;
198 |                 self.selected_index = 0;
199 |                 self.detail_mode = false;
200 |                 self.detail_scroll = 0;
201 |                 self.list_state = ListState::default();
202 |                 if !self.stories.is_empty() {
203 |                     self.list_state.select(Some(0));
204 |                 }
205 |             }
206 |             RalphEvent::IterationStarted {
207 |                 iteration,
208 |                 max_iterations,
209 |             } => {
210 |                 self.current_iteration = iteration;
211 |                 self.max_iterations = max_iterations;
212 |             }
213 |             RalphEvent::StoryStarted { story_id } => {
214 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
215 |                     story.status = RalphStoryStatus::Running;
216 |                     story.steps = 0;
217 |                     story.current_tool = None;
218 |                     story.quality_checks.clear();
219 |                     story.tool_call_history.clear();
220 |                     story.messages.clear();
221 |                     story.output = None;
222 |                     story.error = None;
223 |                 }
224 |             }
225 |             RalphEvent::StoryToolCall {
226 |                 story_id,
227 |                 tool_name,
228 |             } => {
229 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
230 |                     story.current_tool = Some(tool_name);
231 |                     story.steps += 1;
232 |                 }
233 |             }
234 |             RalphEvent::StoryToolCallDetail { story_id, detail } => {
235 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
236 |                     story.current_tool = Some(detail.tool_name.clone());
237 |                     story.steps += 1;
238 |                     story.tool_call_history.push(detail);
239 |                 }
240 |             }
241 |             RalphEvent::StoryMessage { story_id, entry } => {
242 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
243 |                     story.messages.push(entry);
244 |                 }
245 |             }
246 |             RalphEvent::StoryQualityCheck {
247 |                 story_id,
248 |                 check_name,
249 |                 passed,
250 |             } => {
251 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
252 |                     story.status = RalphStoryStatus::QualityCheck;
253 |                     story.current_tool = None;
254 |                     story.quality_checks.push((check_name, passed));
255 |                 }
256 |             }
257 |             RalphEvent::StoryComplete { story_id, passed } => {
258 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
259 |                     story.status = if passed {
260 |                         RalphStoryStatus::Passed
261 |                     } else {
262 |                         RalphStoryStatus::Failed
263 |                     };
264 |                     story.current_tool = None;
265 |                 }
266 |             }
267 |             RalphEvent::StoryOutput { story_id, output } => {
268 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
269 |                     story.output = Some(output);
270 |                 }
271 |             }
272 |             RalphEvent::StoryError { story_id, error } => {
273 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
274 |                     story.error = Some(error.clone());
275 |                     story.status = RalphStoryStatus::Failed;
276 |                 }
277 |             }
278 |             RalphEvent::StoryMerge {
279 |                 story_id,
280 |                 success: _,
281 |                 summary,
282 |             } => {
283 |                 if let Some(story) = self.stories.iter_mut().find(|s| s.id == story_id) {
284 |                     story.merge_summary = Some(summary);
285 |                 }
286 |             }
287 |             RalphEvent::StageComplete { .. } => {
288 |                 // Could track stage progress if needed
289 |             }
290 |             RalphEvent::Complete {
291 |                 status,
292 |                 passed: _,
293 |                 total: _,
294 |             } => {
295 |                 self.complete = true;
296 |                 self.final_status = Some(status);
297 |             }
298 |             RalphEvent::Error(err) => {
299 |                 self.error = Some(err);
300 |             }
301 |         }
302 |     }
303 | 
304 |     /// Move selection up
305 |     pub fn select_prev(&mut self) {
306 |         if self.stories.is_empty() {
307 |             return;
308 |         }
309 |         self.selected_index = self.selected_index.saturating_sub(1);
310 |         self.list_state.select(Some(self.selected_index));
311 |     }
312 | 
313 |     /// Move selection down
314 |     pub fn select_next(&mut self) {
315 |         if self.stories.is_empty() {
316 |             return;
317 |         }
318 |         self.selected_index = (self.selected_index + 1).min(self.stories.len() - 1);
319 |         self.list_state.select(Some(self.selected_index));
320 |     }
321 | 
322 |     /// Enter detail mode for the selected story
323 |     pub fn enter_detail(&mut self) {
324 |         if !self.stories.is_empty() {
325 |             self.detail_mode = true;
326 |             self.detail_scroll = 0;
327 |         }
328 |     }
329 | 
330 |     /// Exit detail mode
331 |     pub fn exit_detail(&mut self) {
332 |         self.detail_mode = false;
333 |         self.detail_scroll = 0;
334 |     }
335 | 
336 |     /// Scroll detail view down
337 |     pub fn detail_scroll_down(&mut self, amount: usize) {
338 |         self.detail_scroll = self.detail_scroll.saturating_add(amount);
339 |     }
340 | 
341 |     /// Scroll detail view up
342 |     pub fn detail_scroll_up(&mut self, amount: usize) {
343 |         self.detail_scroll = self.detail_scroll.saturating_sub(amount);
344 |     }
345 | 
346 |     /// Get the currently selected story
347 |     pub fn selected_story(&self) -> Option<&RalphStoryInfo> {
348 |         self.stories.get(self.selected_index)
349 |     }
350 | 
351 |     /// Status counts
352 |     pub fn status_counts(&self) -> (usize, usize, usize, usize) {
353 |         let mut pending = 0;
354 |         let mut running = 0;
355 |         let mut passed = 0;
356 |         let mut failed = 0;
357 |         for story in &self.stories {
358 |             match story.status {
359 |                 RalphStoryStatus::Pending | RalphStoryStatus::Blocked => pending += 1,
360 |                 RalphStoryStatus::Running | RalphStoryStatus::QualityCheck => running += 1,
361 |                 RalphStoryStatus::Passed => passed += 1,
362 |                 RalphStoryStatus::Failed => failed += 1,
363 |             }
364 |         }
365 |         (pending, running, passed, failed)
366 |     }
367 | 
368 |     /// Overall progress as percentage
369 |     pub fn progress(&self) -> f64 {
370 |         if self.stories.is_empty() {
371 |             return 0.0;
372 |         }
373 |         let (_, _, passed, failed) = self.status_counts();
374 |         ((passed + failed) as f64 / self.stories.len() as f64) * 100.0
375 |     }
376 | }
