484 | fn render_story_list(f: &mut Frame, state: &mut RalphViewState, area: Rect) {
485 |     state.list_state.select(Some(state.selected_index));
486 | 
487 |     let items: Vec<ListItem> = state
488 |         .stories
489 |         .iter()
490 |         .map(|story| {
491 |             let (icon, color) = match story.status {
492 |                 RalphStoryStatus::Pending => ("○", Color::DarkGray),
493 |                 RalphStoryStatus::Blocked => ("⊘", Color::Yellow),
494 |                 RalphStoryStatus::Running => ("●", Color::Cyan),
495 |                 RalphStoryStatus::QualityCheck => ("◎", Color::Magenta),
496 |                 RalphStoryStatus::Passed => ("✓", Color::Green),
497 |                 RalphStoryStatus::Failed => ("✗", Color::Red),
498 |             };
499 | 
500 |             let mut spans = vec![
501 |                 Span::styled(format!("{} ", icon), Style::default().fg(color)),
502 |                 Span::styled(
503 |                     format!("[{}] ", story.id),
504 |                     Style::default().fg(Color::DarkGray),
505 |                 ),
506 |                 Span::styled(&story.title, Style::default().fg(Color::White)),
507 |             ];
508 | 
509 |             // Show current tool for running stories
510 |             if story.status == RalphStoryStatus::Running {
511 |                 if let Some(ref tool) = story.current_tool {
512 |                     spans.push(Span::styled(
513 |                         format!(" → {}", tool),
514 |                         Style::default()
515 |                             .fg(Color::Yellow)
516 |                             .add_modifier(Modifier::DIM),
517 |                     ));
518 |                 }
519 |                 if story.steps > 0 {
520 |                     spans.push(Span::styled(
521 |                         format!(" (step {})", story.steps),
522 |                         Style::default().fg(Color::DarkGray),
523 |                     ));
524 |                 }
525 |             }
526 | 
527 |             // Show quality check status
528 |             if story.status == RalphStoryStatus::QualityCheck {
529 |                 let qc_summary: Vec<&str> = story
530 |                     .quality_checks
531 |                     .iter()
532 |                     .map(|(name, _passed)| name.as_str())
533 |                     .collect();
534 |                 if !qc_summary.is_empty() {
535 |                     let checks: String = story
536 |                         .quality_checks
537 |                         .iter()
538 |                         .map(|(name, passed)| {
539 |                             if *passed {
540 |                                 format!("✓{}", name)
541 |                             } else {
542 |                                 format!("✗{}", name)
543 |                             }
544 |                         })
545 |                         .collect::<Vec<_>>()
546 |                         .join(" ");
547 |                     spans.push(Span::styled(
548 |                         format!(" [{}]", checks),
549 |                         Style::default().fg(Color::Magenta),
550 |                     ));
551 |                 }
552 |             }
553 | 
