904 | /// Truncate a string for display
905 | fn truncate_str(s: &str, max: usize) -> String {
906 |     if s.len() <= max {
907 |         s.replace('\n', " ")
908 |     } else {
909 |         let mut end = max;
910 |         while end > 0 && !s.is_char_boundary(end) {
911 |             end -= 1;
912 |         }
913 |         format!("{}...", s[..end].replace('\n', " "))
914 |     }
915 | }

