    async fn open_ralph_picker(&mut self) {
        self.ralph_picker_prds.clear();
        self.ralph_picker_filter.clear();
        self.ralph_picker_selected = 0;
        self.ralph_picker_mode = RalphPickerMode::Prd;
        self.ralph_picker_loading = true;
        self.view_mode = ViewMode::RalphPicker;

        // Load PRDs from current directory
        let mut prds = Vec::new();
        if let Ok(entries) = std::fs::read_dir(&self.workspace_dir) {
            for entry in entries.flatten() {
                let name = entry.file_name().to_string_lossy().to_string();
                if name.starts_with("prd") && name.ends_with(".json") {
                    if let Ok(content) = std::fs::read_to_string(entry.path()) {
                        if let Ok(prd) = serde_json::from_str::<crate::ralph::types::Prd>(&content) {
                            let total = prd.user_stories.len();
                            let passed = prd.user_stories.iter().filter(|s| s.passes).count();
                            prds.push(RalphPickerEntry {
                                id: name.clone(),
                                title: prd.feature.clone(),
                                subtitle: prd.project.clone(),
                                path_or_status: entry.path().display().to_string(),
                                stories_total: total,
                                stories_passed: passed,
                                created_at: None,
                            });
                        }
                    }
                }
            }
        }

        // Also load OKRs if repository is available
        if let Ok(repo) = crate::okr::OkrRepository::from_config().await {
            if let Ok(okrs) = repo.list_okrs().await {
                for okr in okrs {
                    let total = okr.key_results.len();
                    let status = format!("{:?}", okr.status).to_lowercase();
                    prds.push(RalphPickerEntry {
                        id: okr.id.to_string(),
                        title: okr.title.clone(),
                        subtitle: status.clone(),
                        path_or_status: format!("OKR - {}", status),
                        stories_total: total,
                        stories_passed: 0, // Would need to compute from KRs
                        created_at: Some(okr.created_at.format("%Y-%m-%d %H:%M").to_string()),
                    });
                }
            }
        }

        // Sort by title
        prds.sort_by(|a, b| a.title.cmp(&b.title));

        self.ralph_picker_prds = prds;
        self.ralph_picker_loading = false;
        self.ralph_picker_selected = 0;
    }

    fn filtered_ralph_picker_entries(&self) -> Vec<(usize, &RalphPickerEntry)> {
        if self.ralph_picker_filter.is_empty() {
            return self.ralph_picker_prds.iter().enumerate().collect();
        }

        let filter = self.ralph_picker_filter.to_lowercase();
        self.ralph_picker_prds
            .iter()
            .enumerate()
            .filter(|(_, entry)| {
                entry.title.to_lowercase().contains(&filter)
                    || entry.subtitle.to_lowercase().contains(&filter)
                    || entry.id.to_lowercase().contains(&filter)
            })
            .collect()
    }

